// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới (nếu có)
import { jwtDecode } from 'jwt-decode'; // Import jwtDecode

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '', ghiChu: '', trangThai: 'Hoạt động', // Added trangThai and ghiChu

    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',

    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',

    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',

    // Loại cơ sở đăng ký (dropdown)
    loaiCoSoDangKy: '', // Giá trị mặc định rỗng

    // Thông tin chung cho cả 2 loại (lâm sản và giấy phép)
    tenLamSan: '', tenKhoaHoc: '', issueDate: '', expiryDate: '',
  };

  const [formData, setFormData] = useState(initialFormState);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]); // Dữ liệu đã đọc từ CSV/Excel

  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://localhost:10000/api';

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const decodedToken = jwtDecode(token);
        setIsAdmin(decodedToken.role === 'admin');
      } catch (err) {
        console.error('Lỗi giải mã token:', err);
        setIsAdmin(false);
      }
    }
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDateChange = (e) => {
    const { name, value } = e.target;
    // Chuyển đổi chuỗi ngày thành đối tượng Date hoặc giữ nguyên chuỗi nếu rỗng
    setFormData(prev => ({
      ...prev,
      [name]: value ? new Date(value).toISOString().substring(0, 10) : '' // Lưu dưới dạng YYYY-MM-DD cho input type="date"
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage('');
    setError('');

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn chưa đăng nhập hoặc không có quyền.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };

      // Ensure date fields are in ISO format for backend
      const dataToSend = { ...formData };
      if (dataToSend.ngayThanhLap) dataToSend.ngayThanhLap = new Date(dataToSend.ngayThanhLap).toISOString();
      if (dataToSend.ngayCapCCCD) dataToSend.ngayCapCCCD = new Date(dataToSend.ngayCapCCCD).toISOString();
      if (dataToSend.issueDate) dataToSend.issueDate = new Date(dataToSend.issueDate).toISOString();
      if (dataToSend.expiryDate) dataToSend.expiryDate = new Date(dataToSend.expiryDate).toISOString();

      const response = await axios.post(`${API_BASE_URL}/farms`, dataToSend, config);
      setMessage(response.data.message || 'Đăng ký cơ sở thành công!');
      setFormData(initialFormState); // Reset form
    } catch (err) {
      console.error('Lỗi khi gửi form:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Đã xảy ra lỗi khi đăng ký cơ sở.');
    } finally {
      setIsLoading(false);
    }
  };

  // Hàm mới để parse chuỗi ngày tháng từ CSV
  const parseDateString = (dateString) => {
    if (!dateString) return '';
    // Thử parse các định dạng ngày tháng phổ biến: YYYY-MM-DD, MM/DD/YYYY, DD/MM/YYYY
    // Sử dụng regex để kiểm tra định dạng và parse chính xác hơn
    let date;
    if (dateString.match(/^\d{4}-\d{2}-\d{2}$/)) { // YYYY-MM-DD
      date = new Date(dateString);
    } else if (dateString.match(/^\d{1,2}\/\d{1,2}\/\d{4}$/)) { // MM/DD/YYYY or DD/MM/YYYY
      const parts = dateString.split('/');
      // Giả định MM/DD/YYYY, nếu không đúng có thể cần điều chỉnh
      date = new Date(`${parts[2]}-${parts[0].padStart(2, '0')}-${parts[1].padStart(2, '0')}`);
    } else {
      date = new Date(dateString); // Thử parse mặc định
    }

    if (!isNaN(date.getTime())) {
      return date.toISOString(); // Trả về ISO string nếu là ngày hợp lệ
    }
    return ''; // Trả về chuỗi rỗng nếu không phải ngày hợp lệ
  };

  const handleFileUpload = useCallback((e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        const binaryStr = event.target.result;
        const workbook = XLSX.read(binaryStr, { type: 'binary' }); // Bỏ cellDates ở đây

        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];

        // Sử dụng defval: '' để đảm bảo tất cả các ô đều được đọc, kể cả ô trống
        // raw: true để lấy giá trị thô, sau đó parse ngày tháng thủ công
        const json = XLSX.utils.sheet_to_json(worksheet, {
          header: 1, // Lấy hàng đầu tiên làm tiêu đề
          defval: '', // Giá trị mặc định cho các ô trống
          raw: true, // Lấy giá trị thô
        });

        if (json.length === 0) {
          setError('File CSV rỗng hoặc không có dữ liệu.');
          setExcelData([]);
          return;
        }

        const headers = json[0]; // Hàng đầu tiên là tiêu đề
        const dataRows = json.slice(1); // Các hàng còn lại là dữ liệu

        console.log("Headers from CSV (raw):", headers); // Log tiêu đề thô để debug

        const processedData = dataRows.map((row, rowIndex) => {
          const rowData = {};
          headers.forEach((header, colIndex) => {
            let value = row[colIndex];

            // Đảm bảo giá trị là một chuỗi để xử lý nhất quán
            value = String(value || '');

            // Làm sạch tên tiêu đề: loại bỏ khoảng trắng, ký tự đặc biệt, chuyển sang camelCase
            const cleanedHeader = String(header || '') // Đảm bảo header là chuỗi, xử lý null/undefined
              .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // Loại bỏ dấu tiếng Việt
              .replace(/[^a-zA-Z0-9 ]/g, "") // Loại bỏ ký tự đặc biệt
              .replace(/\s(.)/g, (s) => s.toUpperCase()) // Chuyển sang CamelCase
              .replace(/\s/g, '') // Loại bỏ khoảng trắng còn lại
              .replace(/^(.)/, (s) => s.toLowerCase()); // Chữ cái đầu tiên viết thường

            console.log(`Row ${rowIndex}, Col ${colIndex}: Original Header: "${header}", Cleaned Header: "${cleanedHeader}", Value: "${value}"`);

            // Ánh xạ cụ thể cho các trường có thể có tên/chữ hoa khác nhau trong CSV
            switch (cleanedHeader) {
                // Thông tin cơ sở
                case 'tencoso': rowData.tenCoSo = value; break;
                case 'tinhthanhpho': rowData.tinhThanhPho = value; break;
                case 'xaphuong': rowData.xaPhuong = value; break;
                case 'diachi': rowData.diaChiCoSo = value; break; // Đã sửa từ 'diachicoso' thành 'diachi'
                case 'vido': rowData.vido = value; break;
                case 'kinhdo': rowData.kinhdo = value; break;
                case 'loaihinhcoso': rowData.loaiHinhCoSo = value; break;
                case 'ngaythanhlap': rowData.ngayThanhLap = parseDateString(value); break; // Parse ngày tháng
                case 'sogiayphepkinhdoanh': rowData.giayPhepKinhDoanh = value; break; // Đã sửa từ 'giayphe kinhdoanh'
                case 'ghichu': rowData.ghiChu = value; break;
                case 'trangthai':
                    if (value && typeof value === 'string') {
                        const normalizedStatus = value.trim();
                        if (['Hoạt động', 'Tạm dừng', 'Đình chỉ'].includes(normalizedStatus)) {
                            rowData.trangThai = normalizedStatus;
                        } else {
                            console.warn(`Row ${rowIndex + 2}: Giá trị 'trangThai' không hợp lệ: "${value}". Đặt mặc định 'Hoạt động'.`);
                            rowData.trangThai = 'Hoạt động'; // Mặc định về giá trị enum hợp lệ
                        }
                    } else {
                        console.warn(`Row ${rowIndex + 2}: Giá trị 'trangThai' không phải chuỗi hoặc rỗng: "${value}". Đặt mặc định 'Hoạt động'.`);
                        rowData.trangThai = 'Hoạt động'; // Mặc định nếu không phải chuỗi hoặc rỗng
                    }
                    break;

                // Người đại diện
                case 'hovatennguoidaidien': rowData.tenNguoiDaiDien = value; break; // Đã sửa từ 'tennguoidaidien'
                case 'namsinh': rowData.namSinh = value; break;
                case 'soccdhochie': rowData.soCCCD = value; break; // Đã sửa từ 'socccd'
                case 'ngaycapcccd': rowData.ngayCapCCCD = parseDateString(value); break; // Parse ngày tháng
                case 'noicapcccd': rowData.noiCapCCCD = value; break;
                case 'sodienthoainguoidaidien': rowData.soDienThoaiNguoiDaiDien = value; break;
                case 'diachinguoidaidien': rowData.diaChiNguoiDaiDien = value; break;
                case 'emailnguoidaidien': rowData.emailNguoiDaiDien = value; break;

                // Loại cơ sở đăng ký (RẤT QUAN TRỌNG: Đảm bảo khớp chính xác với enum backend)
                case 'loaicosodangky':
                    if (value && typeof value === 'string') {
                        const normalizedValue = value.trim();
                        if (normalizedValue === 'Đăng ký cơ sở gây nuôi' || normalizedValue === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
                            rowData.loaiCoSoDangKy = normalizedValue;
                        } else {
                            console.warn(`Row ${rowIndex + 2}: Giá trị 'loaiCoSoDangKy' không hợp lệ trong CSV: "${value}". Đặt rỗng.`);
                            rowData.loaiCoSoDangKy = ''; // Để trống nếu không hợp lệ, backend sẽ bắt lỗi nếu là trường bắt buộc
                        }
                    } else {
                        rowData.loaiCoSoDangKy = ''; // Đảm bảo là chuỗi rỗng nếu không phải giá trị hợp lệ
                    }
                    break;

                // Thông tin chung cho cả 2 loại (lâm sản và giấy phép)
                case 'tenlamsan': rowData.tenLamSan = value; break;
                case 'tenkhoahoc': rowData.tenKhoaHoc = value; break;
                case 'ngaycaplicense': rowData.issueDate = parseDateString(value); break; // Parse ngày tháng
                case 'ngayhethanlicense': rowData.expiryDate = parseDateString(value); break; // Parse ngày tháng

                // Thông tin riêng cho Cơ sở gây nuôi
                case 'mucdichnuoi': rowData.mucDichNuoi = value; break;
                case 'hinhthucnuoi': rowData.hinhThucNuoi = value; break;
                case 'masocosogaynuoi': rowData.maSoCoSoGayNuoi = value; break;
                case 'tongdan': rowData.tongDan = value; break;

                // Thông tin riêng cho Cơ sở kinh doanh, chế biến gỗ
                case 'loaihinhkinhdoanhgo': rowData.loaiHinhKinhDoanhGo = value; break;
                case 'nganhnghekinhdoanhgo': rowData.nganhNgheKinhDoanhGo = value; break;
                case 'khoiluong': rowData.khoiLuong = value; break;

                default:
                  // Fallback: Nếu không khớp với các trường cụ thể, gán theo tên đã làm sạch
                  // Chỉ gán nếu trường đó không phải là một trường đã được ánh xạ cụ thể ở trên
                  if (!(cleanedHeader in rowData)) { // Ngăn chặn ghi đè các ánh xạ cụ thể
                    rowData[cleanedHeader] = value;
                  }
                  break;
            }
          });
          console.log(`Row ${rowIndex} processed data:`, rowData); // Log dữ liệu hàng đã xử lý
          return rowData;
        });

        console.log("Dữ liệu đã được xử lý từ CSV (processedData):", processedData);
        setExcelData(processedData);
        setMessage(`Đã đọc được ${processedData.length} dòng dữ liệu từ CSV.`);
        setError('');
      };
      reader.readAsBinaryString(file);
    }
  }, []);

  const handleBulkSubmit = async () => {
    setIsLoading(true);
    setMessage('');
    setError('');

    if (excelData.length === 0) {
      setError('Không có dữ liệu để tải lên hàng loạt.');
      setIsLoading(false);
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn chưa đăng nhập hoặc không có quyền.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      };

      console.log("Dữ liệu gửi đi (Bulk Upload):", excelData); // Log dữ liệu trước khi gửi

      const response = await axios.post(`${API_BASE_URL}/farms/bulk`, excelData, config);
      setMessage(response.data.message || `Đã tải lên thành công ${response.data.savedFarms.length} cơ sở.`);
      if (response.data.errors && response.data.errors.length > 0) {
        setError(`Có lỗi xảy ra với ${response.data.errors.length} cơ sở: ${response.data.errors.map(e => e.message).join(', ')}`);
      }
      setExcelData([]); // Xóa dữ liệu sau khi tải lên thành công
      setCsvFile(null); // Xóa input file
    } catch (err) {
      console.error('Lỗi khi tải lên hàng loạt:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Đã xảy ra lỗi khi tải lên hàng loạt.');
      if (err.response?.data?.errors) {
        // Hiển thị chi tiết lỗi từ backend nếu có
        const backendErrors = err.response.data.errors.map(e => {
          // Kiểm tra nếu 'error' là một đối tượng (từ Mongoose validation)
          if (typeof e.error === 'object' && e.error !== null) {
            const validationMessages = Object.values(e.error).join('; ');
            return `Dòng ${e.index + 2}: ${validationMessages}`; // +2 vì index bắt đầu từ 0 và có hàng tiêu đề
          }
          return `Dòng ${e.index + 2}: ${e.message}`;
        }).join('\n');
        setError(prev => `${prev}\nChi tiết:\n${backendErrors}`);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const resetCsvUpload = () => {
    setCsvFile(null);
    setExcelData([]);
    setMessage('');
    setError('');
    const fileInput = document.getElementById('csvUpload');
    if (fileInput) {
      fileInput.value = ''; // Reset the file input element
    }
  };


  return (
    <div className="khai-bao-co-so-container">
      <h1 className="form-title">Đăng ký Cơ sở Mới</h1>

      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}

      <form onSubmit={handleSubmit} className="khai-bao-form">
        {/* Thông tin cơ sở */}
        <section className="khai-bao-section">
          <h2 className="section-title">Thông tin Cơ sở</h2>
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở (*):</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="tinhThanhPho">Tỉnh/Thành phố (*):</label>
            <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={formData.tinhThanhPho} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="xaPhuong">Xã/Phường (*):</label>
            <input type="text" id="xaPhuong" name="xaPhuong" value={formData.xaPhuong} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở (*):</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={formData.diaChiCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="vido">Vĩ độ:</label>
            <input type="text" id="vido" name="vido" value={formData.vido} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="kinhdo">Kinh độ:</label>
            <input type="text" id="kinhdo" name="kinhdo" value={formData.kinhdo} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
            <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={formData.ngayThanhLap ? formData.ngayThanhLap.substring(0, 10) : ''} onChange={handleDateChange} />
          </div>
          <div className="form-group">
            <label htmlFor="giayPhepKinhDoanh">Giấy phép kinh doanh:</label>
            <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={formData.giayPhepKinhDoanh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ghiChu">Ghi chú:</label>
            <textarea id="ghiChu" name="ghiChu" value={formData.ghiChu} onChange={handleChange}></textarea>
          </div>
          <div className="form-group">
            <label htmlFor="trangThai">Trạng thái:</label>
            <select id="trangThai" name="trangThai" value={formData.trangThai} onChange={handleChange}>
              <option value="Hoạt động">Hoạt động</option>
              <option value="Tạm dừng">Tạm dừng</option>
              <option value="Đình chỉ">Đình chỉ</option>
            </select>
          </div>
        </section>

        {/* Thông tin người đại diện */}
        <section className="khai-bao-section">
          <h2 className="section-title">Thông tin Người đại diện</h2>
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Tên người đại diện:</label>
            <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={formData.tenNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="namSinh">Năm sinh:</label>
            <input type="number" id="namSinh" name="namSinh" value={formData.namSinh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD:</label>
            <input type="text" id="soCCCD" name="soCCCD" value={formData.soCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ngayCapCCCD">Ngày cấp CCCD:</label>
            <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={formData.ngayCapCCCD ? formData.ngayCapCCCD.substring(0, 10) : ''} onChange={handleDateChange} />
          </div>
          <div className="form-group">
            <label htmlFor="noiCapCCCD">Nơi cấp CCCD:</label>
            <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={formData.noiCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại người đại diện:</label>
            <input type="text" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={formData.soDienThoaiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiNguoiDaiDien">Địa chỉ người đại diện:</label>
            <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={formData.diaChiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="emailNguoiDaiDien">Email người đại diện:</label>
            <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={formData.emailNguoiDaiDien} onChange={handleChange} />
          </div>
        </section>

        {/* Loại cơ sở đăng ký (dropdown) */}
        <section className="khai-bao-section">
          <h2 className="section-title">Loại hình đăng ký</h2>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Loại cơ sở đăng ký (*):</label>
            <select
              id="loaiCoSoDangKy"
              name="loaiCoSoDangKy"
              value={formData.loaiCoSoDangKy}
              onChange={handleChange}
              required
            >
              <option value="">-- Chọn loại cơ sở --</option>
              <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>

          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
            <>
              <h3 className="subsection-title">Thông tin Cơ sở gây nuôi</h3>
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <input type="text" id="mucDichNuoi" name="mucDichNuoi" value={formData.mucDichNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <input type="text" id="hinhThucNuoi" name="hinhThucNuoi" value={formData.hinhThucNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở gây nuôi:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={formData.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tongDan">Tổng đàn:</label>
                <input type="number" id="tongDan" name="tongDan" value={formData.tongDan} onChange={handleChange} />
              </div>
            </>
          )}

          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
            <>
              <h3 className="subsection-title">Thông tin Cơ sở kinh doanh, chế biến gỗ</h3>
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <input type="text" id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={formData.loaiHinhKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề kinh doanh gỗ:</label>
                <input type="text" id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={formData.nganhNgheKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="khoiLuong">Khối lượng:</label>
                <input type="number" id="khoiLuong" name="khoiLuong" value={formData.khoiLuong} onChange={handleChange} />
              </div>
            </>
          )}

          {/* Thông tin chung cho cả 2 loại (lâm sản và giấy phép) */}
          {(formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' || formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') && (
            <>
              <h3 className="subsection-title">Thông tin Lâm sản và Giấy phép</h3>
              <div className="form-group">
                <label htmlFor="tenLamSan">Tên lâm sản:</label>
                <input type="text" id="tenLamSan" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
                <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={formData.tenKhoaHoc} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="issueDate">Ngày cấp phép:</label>
                <input type="date" id="issueDate" name="issueDate" value={formData.issueDate ? formData.issueDate.substring(0, 10) : ''} onChange={handleDateChange} />
              </div>
              <div className="form-group">
                <label htmlFor="expiryDate">Ngày hết hạn:</label>
                <input type="date" id="expiryDate" name="expiryDate" value={formData.expiryDate ? formData.expiryDate.substring(0, 10) : ''} onChange={handleDateChange} />
              </div>
            </>
          )}
        </section>

        <button type="submit" className="submit-button" disabled={isLoading}>
          {isLoading ? 'Đang gửi...' : 'Đăng ký Cơ sở'}
        </button>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input
              type="file"
              id="csvUpload"
              accept=".csv"
              onChange={handleFileUpload}
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button
                onClick={handleBulkSubmit}
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button
                onClick={resetCsvUpload}
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
